import React, { useState } from "react";
import { useTranslation } from "react-i18next";
import { 
  theme, Row, Col, Card, Table, Button, Space, Typography, 
  Input, Divider, Modal, Tag, Pagination, Select, Flex, App, Breadcrumb
} from "antd";
import { 
  SearchOutlined, SyncOutlined, 
  AppstoreOutlined, UnorderedListOutlined,
  InfoCircleOutlined, FolderOpenOutlined,
  FilterOutlined, HomeOutlined
} from "@ant-design/icons";

const { useToken } = theme;
const { Title, Text } = Typography;

// --- Interfaces ---
interface DirectoryItem { key: string; name: string; project?: string; count: number; children?: DirectoryItem[]; }
interface ImageData { key: number; name: string; defect: boolean; regDt: string; url: string; size: string; fileSize: string; }

// --- Mock Data ---
const mockDirData: DirectoryItem[] = [
  { key: "d1", name: "resource01", count: 30, children: [
    { key: "d1-1", name: "S63_DATA1", project: "주차관리시스템", count: 13 },
    { key: "d1-2", name: "S63_DATA2", count: 9 },
  ]},
  { key: "d2", name: "resource02", count: 2 },
  { key: "d3", name: "testResource1", count: 43 },
];

export default function ManageImagePage() {
  const { token } = useToken();
  const { t } = useTranslation(["labeling", "project", "common"]);
  const { message } = App.useApp();

  // --- States ---
  const [imageViewMode, setImageViewMode] = useState<"gallery" | "list">("gallery");
  const [isImageDetailOpen, setIsImageDetailOpen] = useState(false);
  const [selectedImage, setSelectedImage] = useState<ImageData | null>(null);
  const [selectedFolder, setSelectedFolder] = useState<string>("resource01");
  const [searchQuery, setSearchQuery] = useState("");
  const [statusFilter, setStatusFilter] = useState<string>("all");

  // --- Logic ---
  const allImages: ImageData[] = Array.from({ length: 24 }).map((_, i) => ({
    key: i,
    name: `IMG_20240407_${1000 + i}.jpg`,
    defect: i % 7 === 0,
    regDt: "2024-04-07 15:44",
    url: `https://picsum.photos/seed/${i + 100}/600/400`,
    size: "1920 x 1080",
    fileSize: "1.2MB"
  }));

  const filteredImages = allImages.filter(img => {
    const matchesSearch = img.name.toLowerCase().includes(searchQuery.toLowerCase());
    const matchesStatus = statusFilter === "all" 
      ? true 
      : (statusFilter === "defect" ? img.defect : !img.defect);
    return matchesSearch && matchesStatus;
  });

  // --- Layout ---
  return (
    <div style={{ padding: "0 24px 24px 24px" }}>
      <style>
        {`
          .image-card-hover:hover {
            transform: translateY(-5px) scale(1.02);
            box-shadow: 0 10px 20px rgba(0,0,0,0.15) !important;
          }
        `}
      </style>
      <div style={{ display: "flex", justifyContent: "space-between", alignItems: "flex-end", marginBottom: 20 }}>
        <div>
          <Title level={4} style={{ margin: 0 }}>{t("navigation.manageImage")}</Title>
        </div>
        <Flex vertical align="flex-end" gap={8}>
          <Breadcrumb 
            items={[
              { title: <Space><HomeOutlined /> {t("listPage.home", { ns: "labeling" })}</Space> },
              { title: t("navigation.manageImage") }
            ]} 
          />
          <Button size="small" icon={<SyncOutlined />} style={{ borderRadius: 6 }}>{t("modal.sync", { ns: "project" })}</Button>
        </Flex>
      </div>

      <Row gutter={20}>
        {/* Left: Directory List */}
        <Col span={7}>
          <Card 
            title={<Space><FolderOpenOutlined /> {t("manage.image.selectFolder")}</Space>}
            variant="borderless" 
            style={{ borderRadius: 12, boxShadow: token.boxShadowTertiary, height: "calc(100vh - 160px)" }}
            styles={{ body: { padding: 0 } }}
          >
            <Table
              dataSource={mockDirData}
              size="small"
              pagination={false}
              rowSelection={{ 
                type: "radio", 
                selectedRowKeys: selectedFolder ? [mockDirData.find(d => d.name === selectedFolder)?.key || ""] : [] 
              }}
              onRow={(item) => ({ 
                onClick: () => setSelectedFolder(item.name), 
                style: { 
                  cursor: "pointer", 
                  background: selectedFolder === item.name ? token.colorPrimaryBg : "transparent" 
                } 
              })}
              columns={[
                { title: t("modal.dirName", { ns: "project" }), dataIndex: "name", key: "name" },
                { 
                  title: t("modal.imgCountInDir", { ns: "project" }), 
                  dataIndex: "count", 
                  key: "cnt", 
                  align: "right",
                  render: (v) => `${v}${t("unit", { ns: "common" })}`
                }
              ]}
              scroll={{ y: "calc(100vh - 260px)" }}
            />
          </Card>
        </Col>

        {/* Right: Image Content */}
        <Col span={17}>
          <Card variant="borderless" style={{ borderRadius: 12, boxShadow: token.boxShadowTertiary, height: "calc(100vh - 160px)" }}>
            <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center", marginBottom: 20 }}>
              <div>
                <Title level={5} style={{ margin: 0 }}>
                  {selectedFolder} 
                  <Text type="secondary" style={{ marginLeft: 8, fontSize: 13, fontWeight: "normal" }}>
                    ({t("total", { ns: "common" })}: {filteredImages.length})
                  </Text>
                </Title>
              </div>
              <Space>
                <Select 
                  defaultValue="all" 
                  size="small" 
                  style={{ width: 100 }}
                  suffixIcon={<FilterOutlined />}
                  onChange={setStatusFilter}
                  options={[
                    { value: "all", label: "ALL" },
                    { value: "normal", label: "NORMAL" },
                    { value: "defect", label: "DEFECT" },
                  ]}
                />
                <Input 
                  prefix={<SearchOutlined />} 
                  placeholder={t("searchPlaceholder", { ns: "common" })} 
                  size="small" 
                  style={{ width: 180 }} 
                  value={searchQuery}
                  onChange={(e) => setSearchQuery(e.target.value)}
                  allowClear
                />
                <Divider orientation="vertical" />
                <Space.Compact size="small">
                  <Button 
                    type={imageViewMode === "gallery" ? "primary" : "default"} 
                    icon={<AppstoreOutlined />} 
                    onClick={() => setImageViewMode("gallery")} 
                  />
                  <Button 
                    type={imageViewMode === "list" ? "primary" : "default"} 
                    icon={<UnorderedListOutlined />} 
                    onClick={() => setImageViewMode("list")} 
                  />
                </Space.Compact>
              </Space>
            </div>

            <div style={{ height: "calc(100vh - 300px)", overflowY: "auto", overflowX: "hidden", padding: "4px" }}>
              {imageViewMode === "gallery" ? (
                <Row gutter={[16, 16]}>
                  {filteredImages.map((img, i) => (
                    <Col span={4} key={img.key}>
                      <Card
                        hoverable
                        styles={{ body: { padding: "8px" } }}
                        onClick={() => {
                          setSelectedImage(img);
                          setIsImageDetailOpen(true);
                        }}
                        cover={
                          <div style={{ height: 110, background: token.colorBgContainerDisabled, display: "flex", alignItems: "center", justifyContent: "center", overflow: "hidden" }}>
                            <img 
                              src={img.url} 
                              alt={`img-${i}`} 
                              style={{ width: "100%", height: "100%", objectFit: "cover" }} 
                            />
                          </div>
                        }
                        style={{ 
                          borderRadius: 8, 
                          overflow: "hidden", 
                          cursor: "pointer",
                          transition: "all 0.3s cubic-bezier(0.4, 0, 0.2, 1)"
                        }}
                        className="image-card-hover"
                      >
                        <Card.Meta 
                          title={<Text ellipsis style={{ fontSize: 11 }}>{img.name}</Text>}
                          description={
                            <div style={{ display: "flex", justifyContent: "space-between", marginTop: 4 }}>
                              <Tag color={img.defect ? "error" : "success"} style={{ fontSize: 9, margin: 0, padding: "0 4px" }}>
                                {img.defect ? "DEFECT" : "NORMAL"}
                              </Tag>
                              <Text type="secondary" style={{ fontSize: 9 }}>15:44</Text>
                            </div>
                          }
                        />
                      </Card>
                    </Col>
                  ))}
                  {filteredImages.length === 0 && (
                    <Col span={24} style={{ textAlign: "center", padding: "100px 0" }}>
                      <Text type="secondary">{t("noObjects", { ns: "common" })}</Text>
                    </Col>
                  )}
                </Row>
              ) : (
                <Table 
                  dataSource={filteredImages}
                  size="small"
                  pagination={false}
                  onRow={(record) => ({
                    onClick: () => {
                      setSelectedImage(record);
                      setIsImageDetailOpen(true);
                    },
                    style: { cursor: "pointer" }
                  })}
                  columns={[
                    { 
                      title: t("manage.image.imgName"), 
                      dataIndex: "name", 
                      key: "name",
                      sorter: (a, b) => a.name.localeCompare(b.name)
                    },
                    { 
                      title: t("manage.image.defect"), 
                      dataIndex: "defect", 
                      key: "defect", 
                      align: "center",
                      filters: [
                        { text: "NORMAL", value: false },
                        { text: "DEFECT", value: true },
                      ],
                      onFilter: (value, record) => record.defect === value,
                      render: (v) => <div style={{ width: 10, height: 10, borderRadius: "50%", background: v ? token.colorError : token.colorSuccess, margin: "auto" }} />
                    },
                    { 
                      title: t("modal.regDt", { ns: "project" }), 
                      dataIndex: "regDt", 
                      key: "dt", 
                      align: "center", 
                      width: 180,
                      sorter: (a, b) => a.regDt.localeCompare(b.regDt)
                    }
                  ]}
                />
              )}
            </div>

            <div style={{ textAlign: "center", marginTop: 20 }}>
              <Pagination total={filteredImages.length} pageSize={filteredImages.length} showSizeChanger={false} />
            </div>
          </Card>
        </Col>
      </Row>

      {/* --- Image Detail Info Popup (Double-Click) --- */}
      <Modal
        title={<Space><InfoCircleOutlined /> {t("manage.image.info")}</Space>}
        open={isImageDetailOpen}
        onCancel={() => setIsImageDetailOpen(false)}
        width={900}
        zIndex={1200}
        footer={null}
        centered
        destroyOnHidden
      >
        <Row gutter={24}>
          <Col span={14}>
            <div style={{ borderRadius: 8, overflow: "hidden", background: "#000", height: 400, display: "flex", alignItems: "center", justifyContent: "center" }}>
              {selectedImage && (
                <img src={selectedImage.url} alt="preview" style={{ maxWidth: "100%", maxHeight: "100%" }} />
              )}
            </div>
          </Col>
          <Col span={10}>
            <div style={{ padding: "0 10px" }}>
              <Flex vertical gap={24} style={{ width: '100%', marginTop: 20 }}>
                <div>
                  <Text type="secondary" style={{ fontSize: 12 }}>{t("manage.image.imgName")}</Text>
                  <div style={{ fontSize: 16, fontWeight: 600 }}>{selectedImage?.name}</div>
                </div>
                <div>
                  <Text type="secondary" style={{ fontSize: 12 }}>{t("manage.image.imgSize")}</Text>
                  <div style={{ fontSize: 16, fontWeight: 600 }}>{selectedImage?.size}</div>
                </div>
                <div>
                  <Text type="secondary" style={{ fontSize: 12 }}>{t("manage.image.fileSize")}</Text>
                  <div style={{ fontSize: 16, fontWeight: 600 }}>{selectedImage?.fileSize}</div>
                </div>
                <div>
                  <Text type="secondary" style={{ fontSize: 12 }}>{t("manage.image.description")}</Text>
                  <div style={{ fontSize: 14 }}>{t("manage.image.noDescription")}</div>
                </div>
              </Flex>

              <div style={{ marginTop: 80, textAlign: "right" }}>
                <Space size={12}>
                  <Button 
                    type="primary" 
                    style={{ background: token.colorSuccess, borderColor: token.colorSuccess, width: 100 }}
                    onClick={() => { message.success(t("manage.image.normalProcessed")); setIsImageDetailOpen(false); }}
                  >
                    {t("manage.image.normal")}
                  </Button>
                  <Button 
                    danger 
                    type="primary" 
                    style={{ width: 100 }}
                    onClick={() => { message.warning(t("manage.image.defectProcessed")); setIsImageDetailOpen(false); }}
                  >
                    {t("manage.image.defect")}
                  </Button>
                  <Button 
                    onClick={() => setIsImageDetailOpen(false)}
                    style={{ width: 100 }}
                  >
                    {t("cancel", { ns: "common" })}
                  </Button>
                </Space>
              </div>
            </div>
          </Col>
        </Row>
      </Modal>
    </div>
  );
}
